from src.nodes.base import BaseNode
from src.utils.prism_core import resolve_prism_core

class PrismStudioAssignProjectNode(BaseNode):
    name = "Prism Studio: Assign User to Project"
    category = "DCCs"

    def __init__(self):
        super().__init__()
        self.icon_path = "icons/prism_icon.png"
        self.add_input("core", "any")
        self.add_input("user", "string", widget_type="text", default="")
        self.add_input("project_path", "string", widget_type="file")
        self.add_output("success", "bool")
        self.add_output("assigned_count", "int")

    async def execute(self, inputs):
        core = resolve_prism_core(inputs)
        user = inputs.get('user') or ''
        proj_path = inputs.get('project_path') or ''
        if core is None or not proj_path:
            self.log_error("Need core and project_path.")
            return {'success': False, 'assigned_count': 0}
        try:
            plugin = core.getPlugin('Studio') if hasattr(core, 'getPlugin') else core.plugins.getPlugin('Studio')
            if plugin is None:
                self.log_error("Studio plugin not loaded.")
                return {'success': False, 'assigned_count': 0}
            if not user:
                user = str(getattr(core, 'username', '') or '')
            cfg_path = core.configs.getProjectConfigPath(proj_path)
            current = plugin.getProjectsForUser(user) or []
            existing_paths = [a.get('configPath') for a in current if isinstance(a, dict)]
            if cfg_path not in existing_paths:
                existing_paths.append(cfg_path)
            plugin.setProjectsAssignedToUsers(users=[user], projects=existing_paths)
            self.log_success(f"Assigned {user} to {len(existing_paths)} project(s).")
            await self.set_output('exec_out', True)
            return {'success': True, 'assigned_count': len(existing_paths)}
        except Exception as e:
            self.log_error(f"assign project failed: {e}")
            return {'success': False, 'assigned_count': 0}

def register_node():
    return PrismStudioAssignProjectNode
